const body = ($('Webhook').first().json.body) || {};
if (!body.project_id) return [{ json: { valid:false, error:'project_id obligatorio' } }];
return [{ json: { valid:true, project_id: body.project_id, send_email: body.send_email !== false } }];

const a = $input.first().json.audit;
const phase = a.project.phase;
const PHASE_RANK = {intake:0, briefing_done:1, design_done:2, analysis_done:3, costs_done:4, trades_done:5, proposal_done:6, approved:7, planning_done:8, completed:9, archived:10};
const rank = PHASE_RANK[phase] !== undefined ? PHASE_RANK[phase] : 0;

// Cada check tiene: id, label, severity, expected (boolean condition), recommendation, only_if_phase_at_least
const checks = [
  // Briefing
  { id:'briefing.exists', label:'Briefing existe', severity:'critical', met: a.briefing.exists, rec:'Generar briefing con agent_briefing.', applicable:true },
  { id:'briefing.approved', label:'Briefing aprobado por arquitecto', severity:'critical', met: a.briefing.approved, rec:'Revisar y aprobar el briefing existente.', applicable: rank >= 1 },
  { id:'briefing.no_open_questions', label:'Briefing sin preguntas abiertas pendientes', severity:'warning', met: a.briefing.has_open_questions === 0, rec:`Resolver ${a.briefing.has_open_questions} preguntas abiertas con el cliente.`, applicable: rank >= 1 },
  // Design
  { id:'design.selected', label:'Design option seleccionada', severity:'critical', met: a.design.selected, rec:'Generar opciones con agent_design y seleccionar una.', applicable: rank >= 1 },
  // Cost estimate
  { id:'costs.has_breakdown', label:'Cost estimate con breakdown', severity:'critical', met: a.cost_estimate.has_breakdown, rec:'Ejecutar agent_costs para generar breakdown detallado.', applicable: rank >= 3 },
  // Materials
  { id:'materials.approved', label:'Materiales aprobados', severity:'warning', met: a.materials.approved > 0, rec:'Revisar y aprobar items propuestos por agent_materials.', applicable: rank >= 3 },
  // Regulatory
  { id:'regulatory.no_pending_critical', label:'Sin tareas reguladoras pendientes', severity:'warning', met: a.regulatory.tasks_pending === 0, rec:`${a.regulatory.tasks_pending} tareas reguladoras sin completar.`, applicable: rank >= 2 },
  { id:'permits.approved', label:'Al menos un permiso aprobado', severity:'critical', met: a.permits.approved > 0, rec:'Necesitas licencia o comunicacion previa antes de iniciar obra.', applicable: rank >= 6 },
  // Proposal
  { id:'proposal.approved', label:'Propuesta comercial aprobada', severity:'critical', met: a.proposal.approved, rec:'Generar propuesta con agent_proposal y enviar al cliente.', applicable: rank >= 5 },
  // Contracts
  { id:'contracts.encargo', label:'Encargo profesional firmado', severity:'critical', met: a.contracts.encargo_signed, rec:'POST /webhook/contract-generate contract_type=encargo_profesional + firma.', applicable: rank >= 6 },
  { id:'contracts.obra', label:'Contrato de obra firmado', severity:'warning', met: a.contracts.obra_signed, rec:'Si la obra la ejecuta tercero: POST /webhook/contract-generate contract_type=contrato_cliente.', applicable: rank >= 7 },
  { id:'contracts.acta_replanteo', label:'Acta de replanteo', severity:'warning', met: a.contracts.acta_replanteo, rec:'Marcar inicio efectivo de obra con acta_replanteo.', applicable: rank >= 7 },
  { id:'contracts.acta_recepcion', label:'Acta recepcion provisional', severity:'critical', met: a.contracts.acta_recepcion_provisional, rec:'Cerrar obra con acta_recepcion_provisional para iniciar plazos LOE.', applicable: rank >= 8 && a.project.has_handover },
  // Safety
  { id:'safety.confirmed', label:'EBSS/PSS confirmado', severity:'critical', met: a.safety.plan_confirmed, rec:'Disparar agent_safety_plan y confirmarlo. RD 1627/1997 obligatorio.', applicable: rank >= 5 },
  // Accessibility
  { id:'accessibility.audited', label:'Auditoria accesibilidad realizada', severity:'warning', met: a.accessibility.audit_done, rec:'Disparar agent_accessibility (CTE DB-SUA).', applicable: rank >= 4 },
  // Energy
  { id:'energy.assessed', label:'Evaluacion energetica estimada', severity:'info', met: a.energy.assessed, rec:'POST /webhook/trigger-energy-assessor para pre-evaluar HE0/HE1.', applicable: rank >= 3 },
  // QC
  { id:'qc.no_blocked', label:'Ningun checklist QC blocked', severity:'warning', met: a.qc.checks_blocked === 0, rec:`${a.qc.checks_blocked} checklists bloqueados con items fail.`, applicable: rank >= 7 },
  // Aftercare
  { id:'aftercare.no_urgent', label:'Sin incidencias aftercare urgentes', severity:'critical', met: a.aftercare.urgent === 0, rec:`${a.aftercare.urgent} incidencias urgentes sin resolver.`, applicable: a.project.has_handover },
  // Pathology
  { id:'pathology.resolved', label:'Patologias detectadas resueltas o descartadas', severity:'warning', met: a.pathology.unresolved === 0, rec:`${a.pathology.unresolved} findings sin resolver.`, applicable: a.pathology.findings_total > 0 },
  // GDPR
  { id:'gdpr.consent', label:'Consentimiento RGPD del cliente registrado', severity:'critical', met: a.gdpr.consent_present, rec:'Insertar consent_records para el client_id.', applicable: true },
  { id:'gdpr.no_pending_requests', label:'Sin solicitudes RGPD pendientes', severity:'warning', met: a.gdpr.requests_pending === 0, rec:`${a.gdpr.requests_pending} solicitudes RGPD pendientes (1 mes max).`, applicable: a.gdpr.requests_pending > 0 }
];

const applicable = checks.filter(c => c.applicable);
const issues = applicable.filter(c => !c.met);
const critical = issues.filter(c => c.severity === 'critical');
const warnings = issues.filter(c => c.severity === 'warning');
const infos = issues.filter(c => c.severity === 'info');

const score = Math.round(100 * (applicable.length - issues.length) / Math.max(applicable.length, 1));
const grade = critical.length > 0 ? 'D' : warnings.length > 2 ? 'C' : warnings.length > 0 ? 'B' : 'A';

return [{ json: {
  project_id: a.project.id,
  project_name: a.project.name,
  current_phase: phase,
  audit_summary: {
    score: score,
    grade: grade,
    applicable_checks: applicable.length,
    passed: applicable.length - issues.length,
    failed: issues.length,
    critical_count: critical.length,
    warning_count: warnings.length,
    info_count: infos.length
  },
  issues: issues.map(i => ({ id: i.id, label: i.label, severity: i.severity, recommendation: i.rec })),
  passed: applicable.filter(c => c.met).map(c => c.id),
  raw: a
}}];

const r = $input.first().json;
const summary = r.audit_summary;
const gradeColor = { A: '#27ae60', B: '#f1c40f', C: '#e67e22', D: '#e74c3c' };
const sevColor = { critical: '#e74c3c', warning: '#e67e22', info: '#3498db' };
const issueRows = (r.issues || []).map(i => '<tr>' +
  '<td><span style=\"background:' + sevColor[i.severity] + ';color:white;padding:3px 8px;border-radius:12px;font-size:11px\">' + i.severity.toUpperCase() + '</span></td>' +
  '<td>' + i.label + '</td>' +
  '<td style=\"font-size:12px;color:#7f8c8d\">' + i.recommendation + '</td>' +
  '</tr>').join('');
const html = '<div style=\"font-family:Arial,sans-serif;max-width:720px;margin:0 auto\">' +
  '<h2 style=\"color:#2c3e50\">Compliance Audit — ' + r.project_name + '</h2>' +
  '<table style=\"width:100%;border-collapse:collapse;margin:16px 0\">' +
  '<tr><td style=\"padding:8px;background:#f3f4f6\"><b>Score</b></td><td style=\"padding:8px\"><span style=\"background:' + gradeColor[summary.grade] + ';color:white;padding:6px 16px;border-radius:6px;font-size:20px;font-weight:bold\">' + summary.grade + '</span> &nbsp;&nbsp; ' + summary.score + ' / 100 (' + summary.passed + '/' + summary.applicable_checks + ' checks)</td></tr>' +
  '<tr><td style=\"padding:8px;background:#f3f4f6\"><b>Fase actual</b></td><td style=\"padding:8px\">' + r.current_phase + '</td></tr>' +
  '<tr><td style=\"padding:8px;background:#f3f4f6\"><b>Issues</b></td><td style=\"padding:8px\">' + summary.critical_count + ' critical · ' + summary.warning_count + ' warning · ' + summary.info_count + ' info</td></tr>' +
  '</table>' +
  (issueRows ? '<h3>Items pendientes</h3><table border=\"1\" cellpadding=\"6\" cellspacing=\"0\" style=\"border-collapse:collapse;font-family:sans-serif;font-size:13px\"><thead><tr style=\"background:#f3f4f6\"><th>Severidad</th><th>Check</th><th>Accion recomendada</th></tr></thead><tbody>' + issueRows + '</tbody></table>' : '<p style=\"color:#27ae60\">✅ Sin issues pendientes para la fase actual.</p>') +
  '<p style=\"font-size:11px;color:#95a5a6\">Audit ID: ' + Date.now() + ' — endpoint: POST /webhook/audit-project</p>' +
  '</div>';
return [{ json: { html_body: html, project_name: r.project_name, score: summary.score, grade: summary.grade, critical_count: summary.critical_count } }];
